package main

import (
	"context"
	"os"
	"path/filepath"
	"testing"

	"github.com/aquasecurity/fanal/analyzer"
	ftypes "github.com/aquasecurity/fanal/types"
	"github.com/future-architect/vuls/models"
	"github.com/future-architect/vuls/scanner"
)

// TestRegression validates that library scanner properly handles:
// 1. Trivy DB client initialization with all required parameters
// 2. PNPM and .NET ecosystem detection
// 3. Proper analyzer scope control for library-only scans
func TestRegression(t *testing.T) {
	t.Run("PNPM_Ecosystem_Detection", testPNPMEcosystemDetection)
	t.Run("DotNet_Ecosystem_Detection", testDotNetEcosystemDetection)
	t.Run("Analyzer_Scope_Control", testAnalyzerScopeControl)
	t.Run("Library_Map_Completeness", testLibraryMapCompleteness)
	t.Run("Trivy_DB_Client_Initialization", testTrivyDBClientInitialization)
}

// testPNPMEcosystemDetection validates that PNPM lockfiles are properly recognized
func testPNPMEcosystemDetection(t *testing.T) {
	// PNPM uses pnpm-lock.yaml as its lockfile
	pnpmLockfile := "pnpm-lock.yaml"

	// Check if PNPM lockfile is in the LibraryMap
	if _, exists := models.LibraryMap[pnpmLockfile]; !exists {
		t.Errorf("PNPM lockfile '%s' not found in LibraryMap. PNPM projects will not be scanned for vulnerabilities.", pnpmLockfile)
	}

	// Check if library type is correctly mapped to "node" ecosystem
	if models.LibraryMap[pnpmLockfile] != "node" {
		t.Errorf("PNPM lockfile should map to 'node' ecosystem, got '%s'", models.LibraryMap[pnpmLockfile])
	}

	// Verify that PNPM packages can be processed
	libScanner := models.LibraryScanner{
		Type:         "pnpm",
		LockfilePath: "/app/pnpm-lock.yaml",
		Libs: []models.Library{
			{Name: "lodash", Version: "4.17.20"},
		},
	}

	// This should not panic - PNPM type should be recognized
	key := libScanner.GetLibraryKey()
	if key != "node" {
		t.Errorf("PNPM scanner should return library key 'node', got '%s'", key)
	}
}

// testDotNetEcosystemDetection validates that .NET lockfiles are properly recognized
func testDotNetEcosystemDetection(t *testing.T) {
	testCases := []struct {
		name     string
		filename string
		expected string
	}{
		{
			name:     "NuGet packages lock",
			filename: ftypes.NuGetPkgsLock,
			expected: ".net",
		},
		{
			name:     "NuGet packages config",
			filename: ftypes.NuGetPkgsConfig,
			expected: ".net",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			if _, exists := models.LibraryMap[tc.filename]; !exists {
				t.Errorf(".NET lockfile '%s' not found in LibraryMap", tc.filename)
			}

			if models.LibraryMap[tc.filename] != tc.expected {
				t.Errorf("Expected '%s' for %s, got '%s'", tc.expected, tc.filename, models.LibraryMap[tc.filename])
			}
		})
	}

	// Verify NuGet type is recognized
	libScanner := models.LibraryScanner{
		Type:         ftypes.NuGet,
		LockfilePath: "/app/packages.lock.json",
		Libs: []models.Library{
			{Name: "Newtonsoft.Json", Version: "13.0.1"},
		},
	}

	key := libScanner.GetLibraryKey()
	if key != ".net" {
		t.Errorf("NuGet scanner should return library key '.net', got '%s'", key)
	}
}

// testAnalyzerScopeControl validates that non-library analyzers are disabled during library scans
func testAnalyzerScopeControl(t *testing.T) {
	tmpDir := t.TempDir()

	// Create a minimal npm package.json
	packageJson := `{"name": "test", "version": "1.0.0", "dependencies": {}}`
	lockfilePath := filepath.Join(tmpDir, "package-lock.json")
	if err := os.WriteFile(lockfilePath, []byte(packageJson), 0644); err != nil {
		t.Fatalf("Failed to create test lockfile: %v", err)
	}

	libFilemap := map[string]scanner.LibFile{
		lockfilePath: {
			Contents: []byte(packageJson),
			Filemode: 0644,
		},
	}

	// Perform library analysis
	libraryScanners, err := scanner.AnalyzeLibraries(context.Background(), libFilemap, false)
	if err != nil {
		// This error is expected if the analyzer is not properly configured for library-only mode
		// The test verifies that the function attempts proper scope control
		t.Logf("AnalyzeLibraries encountered error (expected during regression): %v", err)
	}

	// Verify that the analyzer group is being used
	if len(libraryScanners) == 0 && err == nil {
		t.Logf("AnalyzeLibraries returned no scanners (may be expected for empty lockfile)")
	}
}

// testLibraryMapCompleteness checks that common ecosystem lockfiles are in the map
func testLibraryMapCompleteness(t *testing.T) {
	requiredMappings := map[string]string{
		ftypes.NpmPkgLock:      "node",
		ftypes.YarnLock:        "node",
		ftypes.GemfileLock:     "ruby",
		ftypes.CargoLock:       "rust",
		ftypes.ComposerLock:    "php",
		ftypes.PipRequirements: "python",
		ftypes.PipfileLock:     "python",
		ftypes.PoetryLock:      "python",
		ftypes.NuGetPkgsLock:   ".net",
		ftypes.NuGetPkgsConfig: ".net",
		ftypes.GoMod:           "gomod",
		ftypes.MavenPom:        "java",
	}

	missingEcosystems := []string{}
	for filename, expectedType := range requiredMappings {
		if actualType, exists := models.LibraryMap[filename]; !exists {
			missingEcosystems = append(missingEcosystems, filename)
		} else if actualType != expectedType {
			t.Errorf("LibraryMap[%s] = %s, expected %s", filename, actualType, expectedType)
		}
	}

	if len(missingEcosystems) > 0 {
		t.Errorf("Missing ecosystems in LibraryMap: %v. Projects using these package managers will have zero vulnerability findings.", missingEcosystems)
	}
}

// testTrivyDBClientInitialization validates that Trivy DB client is initialized correctly
func testTrivyDBClientInitialization(t *testing.T) {
	// This test validates the API contract for db.NewClient
	// The current code uses: db.NewClient(cacheDir, quiet)
	// Newer Trivy versions may require additional parameters

	tmpDir := t.TempDir()

	// Verify that the detector module can be imported and compiled
	// The import path for trivy db should be accessible
	libDetectorCode := `
package main
import (
	"github.com/aquasecurity/trivy/pkg/db"
)
func testDBClient() {
	// Current code pattern from detector/library.go line 66:
	// client := db.NewClient(cacheDir, quiet)
	// This will fail if NewClient signature has changed to require additional parameters
	cacheDir := "/tmp/test"
	quiet := false

	// This validates the old API is still working
	_ = db.NewClient(cacheDir, quiet)
}
`

	t.Logf("Trivy DB client API validation:\n%s", libDetectorCode)

	// Verify detector/library.go imports are correct
	detectorLibraryPath := "/app/detector/library.go"
	content, err := os.ReadFile(detectorLibraryPath)
	if err != nil {
		t.Fatalf("Failed to read detector/library.go: %v", err)
	}

	// Check that db.NewClient is being called with the correct parameters
	contentStr := string(content)
	if !contains(contentStr, "db.NewClient(cacheDir, quiet)") &&
		!contains(contentStr, "db.NewClient(cacheDir,quiet)") {
		t.Logf("WARNING: detector/library.go does not use expected db.NewClient call pattern. May indicate API mismatch.")
	}

	// Verify trivy-db import is present
	if !contains(contentStr, `trivydb "github.com/aquasecurity/trivy-db/pkg/db"`) {
		t.Logf("WARNING: trivy-db import may be missing from detector/library.go")
	}
}

// contains is a helper function to check if a string contains a substring
func contains(s, substr string) bool {
	return len(s) > 0 && len(substr) > 0 && (s == substr || len(s) > len(substr) &&
		(s[:len(substr)] == substr || s[len(s)-len(substr):] == substr ||
		indexStr(s, substr) >= 0))
}

// indexStr finds the index of substring in string
func indexStr(s, substr string) int {
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return i
		}
	}
	return -1
}

// TestRegressionIncompleteScanScope validates that library-only scans don't include unnecessary analyzers
func TestRegressionIncompleteScanScope(t *testing.T) {
	// The issue: "Incomplete scan scope control: During library scans, non-application analyzers
	// (OS packaging, secrets, licenses) may execute unnecessarily, producing noise in the results
	// and slowing scans."

	// Validate that the list of disabled analyzers in scanner/base.go AnalyzeLibraries
	// includes all non-library analyzer types

	expectedDisabledTypes := []analyzer.Type{
		// OS package analyzers
		analyzer.TypeAlpine,
		analyzer.TypeAlma,
		analyzer.TypeAmazon,
		analyzer.TypeDebian,
		analyzer.TypePhoton,
		analyzer.TypeCentOS,
		analyzer.TypeFedora,
		analyzer.TypeOracle,
		analyzer.TypeRedHatBase,
		analyzer.TypeRocky,
		analyzer.TypeSUSE,
		analyzer.TypeUbuntu,
		analyzer.TypeApk,
		analyzer.TypeDpkg,
		analyzer.TypeRpm,
		analyzer.TypeApkCommand,
		// Config file analyzers
		analyzer.TypeYaml,
		analyzer.TypeTOML,
		analyzer.TypeJSON,
		analyzer.TypeDockerfile,
		analyzer.TypeHCL,
		// Security-related analyzers
		analyzer.TypeSecret,
		// License analyzer (may be missing)
		// analyzer.TypeLicense,
	}

	t.Logf("Expected disabled analyzers during library scans: %d types", len(expectedDisabledTypes))

	// Check if scanner/base.go has the complete list
	baseGoPath := "/app/scanner/base.go"
	content, err := os.ReadFile(baseGoPath)
	if err != nil {
		t.Fatalf("Failed to read scanner/base.go: %v", err)
	}

	contentStr := string(content)

	// Look for analyzer.TypeLicense which might be missing
	if !contains(contentStr, "analyzer.TypeLicense") {
		t.Logf("REGRESSION: analyzer.TypeLicense not found in disabled analyzers list. License scanning may run unnecessarily during library scans.")
	}

	// Verify the analyzer group is properly configured
	if !contains(contentStr, "analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)") {
		t.Logf("WARNING: analyzer group configuration may differ from expected pattern")
	}
}

